function esc(str) {
  return String(str || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const jobs = $input.first().json.stellenangebote || [];

// Timestamps ohne Zeitzone als lokale Zeit (CET/CEST) parsen
function parseTimestamp(ts) {
  if (!ts) return null;
  if (/Z$|[+-]\d{2}:\d{2}$/.test(ts)) return new Date(ts);
  const offset = new Date().getTimezoneOffset(); // -60 fuer CET, -120 fuer CEST
  const sign = offset <= 0 ? '+' : '-';
  const h = String(Math.floor(Math.abs(offset) / 60)).padStart(2, '0');
  const m = String(Math.abs(offset) % 60).padStart(2, '0');
  return new Date(ts + sign + h + ':' + m);
}

// Nur Jobs der letzten 15 Minuten + 10 Sekunden
const cutoff = new Date(Date.now() - 910 * 1000);
const recentJobs = jobs.filter(job => {
  if (!job.modifikationsTimestamp) return false;
  return parseTimestamp(job.modifikationsTimestamp) >= cutoff;
});

// Bereits gesendete Job-IDs laden (persistent über Runs)
const staticData = $getWorkflowStaticData('global');
if (!staticData.sentIds) staticData.sentIds = {};

// Alte Einträge aufräumen (älter als 7 Tage)
const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
for (const id of Object.keys(staticData.sentIds)) {
  if (staticData.sentIds[id] < sevenDaysAgo) delete staticData.sentIds[id];
}

// Nur Jobs, die noch nicht gesendet wurden
const newJobs = recentJobs.filter(job => {
  const id = job.refnr;
  if (!id) return false;
  return !staticData.sentIds[id];
});

if (newJobs.length === 0) {
  return [{ json: { hasJobs: false, telegramText: '', jobCount: 0 } }];
}

// Neue IDs als gesendet markieren
for (const job of newJobs) {
  staticData.sentIds[job.refnr] = Date.now();
}

let text = '';
newJobs.forEach((job, i) => {
  const titel = esc(job.titel);
  const arbeitgeber = esc(job.arbeitgeber);
  const ort = esc(job.arbeitsort?.ort || job.arbeitsort?.plz || 'k.A.');
  const refnr = job.refnr || '';
  const jobUrl = job.externeUrl ? job.externeUrl : `https://www.arbeitsagentur.de/jobsuche/jobdetail/${refnr}`;
  const veroeffentlicht = job.aktuelleVeroeffentlichungsdatum
    ? new Date(job.aktuelleVeroeffentlichungsdatum).toLocaleDateString('de-DE')
    : 'k.A.';
  const modified = job.modifikationsTimestamp
    ? new Date(job.modifikationsTimestamp).toLocaleString('de-DE')
    : 'k.A.';
  const arbeitszeit = Array.isArray(job.arbeitszeit)
    ? esc(job.arbeitszeit.join(', '))
    : esc(job.arbeitszeit || 'k.A.');

  text += `<b>${i + 1}. ${titel}</b>\n`;
  text += `Arbeitgeber: ${arbeitgeber}\n`;
  text += `Ort: ${ort}\n`;
  text += `Arbeitszeit: ${arbeitszeit}\n`;
  text += `Veroeffentlicht: ${veroeffentlicht}\n`;
  text += `Aktualisiert: ${modified}\n`;
  text += `<a href='${jobUrl}'>Zur Stelle</a>\n\n`;
});

return [{ json: { hasJobs: true, telegramText: text, jobCount: newJobs.length } }];
